description:
Implement protocol configuration and loading:

```go
// protocol.go
package main

import (
    "fmt"
    "os"
    "path/filepath"
    "time"
)

type Protocol struct {
    Name       string
    Content    string        // Loaded protocol markdown
    Model      string        // gemini-3-flash-preview or gemini-3-pro-preview
    OutputJSON bool          // Force -o json for this protocol
    Timeout    time.Duration
}

var defaultConfig = map[string]struct {
    Model      string
    OutputJSON bool
    Timeout    time.Duration
}{
    // Fast protocols (Flash) - JSON output
    "mapper":          {"gemini-3-flash-preview", true, 60 * time.Second},
    "memory-drift":    {"gemini-3-flash-preview", true, 60 * time.Second},
    "benchmark-score": {"gemini-3-flash-preview", true, 60 * time.Second},
    "deps":            {"gemini-3-flash-preview", true, 90 * time.Second},
    "api-surface":     {"gemini-3-flash-preview", true, 90 * time.Second},

    // Complex protocols (Pro) - Markdown default
    "architect":       {"gemini-3-pro-preview", false, 180 * time.Second},
    "debugger":        {"gemini-3-pro-preview", false, 180 * time.Second},
    "memory-audit":    {"gemini-3-pro-preview", false, 300 * time.Second},
    "benchmark-audit": {"gemini-3-pro-preview", false, 300 * time.Second},
}

func LoadProtocol(name string) (*Protocol, error) {
    home, _ := os.UserHomeDir()
    path := filepath.Join(home, ".gemini-slave/protocols", name+".md")

    content, err := os.ReadFile(path)
    if err != nil {
        return nil, fmt.Errorf("protocol '%s' not found: %w", name, err)
    }

    cfg, ok := defaultConfig[name]
    if !ok {
        // Unknown protocol - use Flash, no JSON, 60s timeout
        cfg = struct{ Model string; OutputJSON bool; Timeout time.Duration }{
            "gemini-3-flash-preview", false, 60 * time.Second,
        }
    }

    return &Protocol{
        Name:       name,
        Content:    string(content),
        Model:      cfg.Model,
        OutputJSON: cfg.OutputJSON,
        Timeout:    cfg.Timeout,
    }, nil
}

func ListProtocols() ([]string, error) {
    home, _ := os.UserHomeDir()
    dir := filepath.Join(home, ".gemini-slave/protocols")

    entries, err := os.ReadDir(dir)
    if err != nil {
        return nil, err
    }

    var names []string
    for _, e := range entries {
        if filepath.Ext(e.Name()) == ".md" {
            names = append(names, strings.TrimSuffix(e.Name(), ".md"))
        }
    }
    return names, nil
}
```

Support GEMINI_MODEL env var override.
